const response = items[0].json ?? {};
const vulnerabilities = response.vulnerabilities ?? [];

function getCvss(cve) {
  const metrics = cve?.metrics ?? {};
  const v31 = metrics.cvssMetricV31?.[0]?.cvssData?.baseScore;
  const v30 = metrics.cvssMetricV30?.[0]?.cvssData?.baseScore;
  const v2 = metrics.cvssMetricV2?.[0]?.baseScore;
  return Number(v31 ?? v30 ?? v2 ?? 0);
}

function getDescription(cve) {
  const descriptions = cve?.descriptions ?? [];
  const english = descriptions.find((entry) => entry.lang === 'en');
  return english?.value ?? descriptions[0]?.value ?? 'Sin descripción';
}

function getAffectedSoftware(vuln) {
  const nodes = vuln?.configurations?.[0]?.nodes ?? [];
  for (const node of nodes) {
    const matches = node.cpeMatch ?? [];
    if (matches.length > 0) {
      const raw = matches[0].criteria || matches[0].cpe23Uri || 'unknown';
      const parts = String(raw).split(':');
      return parts.slice(0, 5).join(':');
    }
  }
  return 'unknown';
}

const normalized = vulnerabilities.map((vuln) => {
  const cve = vuln.cve ?? {};
  const cveId = cve.id ?? 'unknown';
  const description = getDescription(cve);
  const cvss = getCvss(cve);
  const affectedSoftware = getAffectedSoftware(vuln);
  const epss = Number((0.05 + Math.random() * 0.9).toFixed(3));

  return {
    json: {
      cveId,
      description,
      cvss,
      epss,
      affectedSoftware
    }
  };
});

return normalized;

const criticalityByAsset = {
  nginx: { assetName: 'Servidor Nginx', criticality: 'alta', weight: 1.0 },
  wordpress: { assetName: 'WordPress', criticality: 'alta', weight: 1.0 },
  apache: { assetName: 'Servidor Apache', criticality: 'media', weight: 0.5 },
  tomcat: { assetName: 'Servidor Tomcat', criticality: 'media', weight: 0.5 }
};

function detectAsset(text) {
  const content = String(text).toLowerCase();
  for (const [keyword, value] of Object.entries(criticalityByAsset)) {
    if (content.includes(keyword)) {
      return value;
    }
  }
  return { assetName: 'Pendiente de identificar', criticality: 'baja', weight: 0.2 };
}

function getRiskLabel(irc) {
  if (irc >= 0.75) return 'alta';
  if (irc >= 0.45) return 'media';
  return 'baja';
}

const enriched = items.map((item) => {
  const current = item.json;
  const detected = detectAsset(`${current.cveId} ${current.description} ${current.affectedSoftware}`);
  const cvssNormalized = Math.max(0, Math.min(10, Number(current.cvss ?? 0))) / 10;
  const epssNormalized = Math.max(0, Math.min(1, Number(current.epss ?? 0)));
  const irc = Number(((cvssNormalized * 0.4) + (epssNormalized * 0.4) + (detected.weight * 0.2)).toFixed(4));

  return {
    json: {
      ...current,
      assetName: detected.assetName,
      criticality: detected.criticality,
      assignedTo: 'Pendiente',
      irc,
      ircLevel: getRiskLabel(irc)
    }
  };
});

return enriched;

const vulnerabilities = items.map((item) => item.json);

const counts = vulnerabilities.reduce((acc, vuln) => {
  acc.total += 1;
  acc[vuln.ircLevel] = (acc[vuln.ircLevel] ?? 0) + 1;
  return acc;
}, { total: 0, alta: 0, media: 0, baja: 0 });

const payload = {
  generatedAt: new Date().toISOString(),
  source: 'NVD API',
  total: counts.total,
  summary: {
    alta: counts.alta,
    media: counts.media,
    baja: counts.baja
  },
  vulnerabilities
};

return [
  {
    json: payload
  }
];
